<?php
 namespace League\CommonMark\Extension\Autolink; use League\CommonMark\Extension\Mention\MentionParser; use League\CommonMark\Inline\Element\Link; use League\CommonMark\Inline\Parser\InlineParserInterface; use League\CommonMark\InlineParserContext; @trigger_error(sprintf('%s is deprecated; use %s instead', InlineMentionParser::class, MentionParser::class), E_USER_DEPRECATED); final class InlineMentionParser implements InlineParserInterface { private $linkPattern; private $handleRegex; public function __construct($linkPattern, $handleRegex = '/^[A-Za-z0-9_]+(?!\w)/') { $this->linkPattern = $linkPattern; $this->handleRegex = $handleRegex; } public function getCharacters(): array { return ['@']; } public function parse(InlineParserContext $inlineContext): bool { $cursor = $inlineContext->getCursor(); $previousChar = $cursor->peek(-1); if ($previousChar !== null && $previousChar !== ' ') { return false; } $previousState = $cursor->saveState(); $cursor->advance(); $handle = $cursor->match($this->handleRegex); if (empty($handle)) { $cursor->restoreState($previousState); return false; } $url = \sprintf($this->linkPattern, $handle); $inlineContext->getContainer()->appendChild(new Link($url, '@' . $handle)); return true; } public static function createTwitterHandleParser() { return new self('https://twitter.com/%s', '/^[A-Za-z0-9_]{1,15}(?!\w)/'); } public static function createGithubHandleParser() { return new self('https://www.github.com/%s', '/^[a-z\d](?:[a-z\d]|-(?=[a-z\d])){0,38}(?!\w)/'); } } 